const initialState = {
  tasks: [],
  filter: 'all', // 'all', 'pending', 'in-progress', 'completed'
  sortBy: 'priority' // 'priority' ou 'date'
};

function taskReducer(state, action) {
  switch (action.type) {
    case 'ADD_TASK':
      const newTask = {
        id: Date.now(),
        ...action.payload,
        status: 'pending',
        createdAt: new Date().toISOString()
      };
      return { ...state, tasks: [...state.tasks, newTask] };

    case 'UPDATE_STATUS':
      return {
        ...state,
        tasks: state.tasks.map(task =>
          task.id === action.payload.id
            ? { ...task, status: action.payload.status }
            : task
        )
      };

    case 'UPDATE_PRIORITY':
      return {
        ...state,
        tasks: state.tasks.map(task =>
          task.id === action.payload.id
            ? { ...task, priority: action.payload.priority }
            : task
        )
      };

    case 'DELETE_TASK':
      return {
        ...state,
        tasks: state.tasks.filter(task => task.id !== action.payload)
      };

    case 'SET_FILTER':
      return { ...state, filter: action.payload };

    case 'SET_SORT':
      return { ...state, sortBy: action.payload };

    case 'COMPLETE_ALL':
      return {
        ...state,
        tasks: state.tasks.map(task =>
          task.status !== 'completed'
            ? { ...task, status: 'completed' }
            : task
        )
      };

    case 'DELETE_COMPLETED':
      return {
        ...state,
        tasks: state.tasks.filter(task => task.status !== 'completed')
      };

    default:
      return state;
  }
}

// Selecteurs pour filtrer et trier (à utiliser dans le composant)
function getFilteredAndSortedTasks(state) {
  let filtered = state.tasks;

  if (state.filter !== 'all') {
    filtered = filtered.filter(task => task.status === state.filter);
  }

  const priorityOrder = { high: 3, medium: 2, low: 1 };
  if (state.sortBy === 'priority') {
    filtered = [...filtered].sort((a, b) => priorityOrder[b.priority] - priorityOrder[a.priority]);
  }

  return filtered;
}
